 1→import type { SDUIContext, SDUIContextValue } from '../models';
 2→
 3→const INTERPOLATION_REGEX = /\{\{([^}]+)\}\}/g;
 4→
 5→export function resolveContextPath(
 6→  context: SDUIContext,
 7→  path: string,
 8→): SDUIContextValue {
 9→  const segments = path.trim().split('.');
10→  let current: SDUIContextValue = context;
11→
12→  for (const segment of segments) {
13→    if (current === null || current === undefined) return '';
14→    if (typeof current !== 'object') return '';
15→
16→    if (Array.isArray(current)) {
17→      const index = parseInt(segment, 10);
18→      if (isNaN(index) || index < 0 || index >= current.length) return '';
19→      current = current[index] as SDUIContextValue;
20→    } else {
21→      current = (current as SDUIContext)[segment];
22→    }
23→  }
24→
25→  return current ?? '';
26→}
27→
28→export function interpolateString(
29→  template: string,
30→  context: SDUIContext,
31→): string {
32→  return template.replace(INTERPOLATION_REGEX, (_, path: string) => {
33→    const value = resolveContextPath(context, path);
34→    if (value === null || value === undefined) return '';
35→    if (typeof value === 'object') return '';
36→    return String(value);
37→  });
38→}
39→
40→export function interpolateDeep<T>(value: T, context: SDUIContext): T {
41→  if (typeof value === 'string') {
42→    return interpolateString(value, context) as T;
43→  }
44→
45→  if (Array.isArray(value)) {
46→    return value.map(item => interpolateDeep(item, context)) as T;
47→  }
48→
49→  if (value !== null && typeof value === 'object') {
50→    const result: Record<string, unknown> = {};
51→    for (const key of Object.keys(value)) {
52→      result[key] = interpolateDeep(
53→        (value as Record<string, unknown>)[key],
54→        context,
55→      );
56→    }
57→    return result as T;
58→  }
59→
60→  return value;
61→}
