  1→import type { SDUIContext } from '../models';
  2→import {
  3→  resolveContextPath,
  4→  interpolateString,
  5→  interpolateDeep,
  6→} from './interpolation';
  7→
  8→const CONTEXT: SDUIContext = {
  9→  product: {
 10→    key: 'abastecimento',
 11→    name: 'Abastecimento',
 12→    code: 206,
 13→  },
 14→  balance: {
 15→    points: 25720,
 16→    pointsFormatted: '25.720',
 17→    value: 7716.0,
 18→    valueFormatted: 'R$ 7.716,00',
 19→  },
 20→  empty: null,
 21→  tags: ['premium', 'active'],
 22→};
 23→
 24→describe('resolveContextPath', () => {
 25→  it('resolves top-level keys', () => {
 26→    const ctx: SDUIContext = { greeting: 'hello' };
 27→    expect(resolveContextPath(ctx, 'greeting')).toBe('hello');
 28→  });
 29→
 30→  it('resolves nested paths', () => {
 31→    expect(resolveContextPath(CONTEXT, 'product.name')).toBe('Abastecimento');
 32→    expect(resolveContextPath(CONTEXT, 'balance.pointsFormatted')).toBe(
 33→      '25.720',
 34→    );
 35→  });
 36→
 37→  it('resolves numeric values', () => {
 38→    expect(resolveContextPath(CONTEXT, 'product.code')).toBe(206);
 39→    expect(resolveContextPath(CONTEXT, 'balance.points')).toBe(25720);
 40→  });
 41→
 42→  it('returns empty string for missing paths', () => {
 43→    expect(resolveContextPath(CONTEXT, 'nonexistent')).toBe('');
 44→    expect(resolveContextPath(CONTEXT, 'product.missing')).toBe('');
 45→    expect(resolveContextPath(CONTEXT, 'a.b.c.d')).toBe('');
 46→  });
 47→
 48→  it('returns empty string for null values', () => {
 49→    expect(resolveContextPath(CONTEXT, 'empty')).toBe('');
 50→  });
 51→
 52→  it('handles whitespace in path', () => {
 53→    expect(resolveContextPath(CONTEXT, ' product.name ')).toBe(
 54→      'Abastecimento',
 55→    );
 56→  });
 57→
 58→  it('resolves array elements by index', () => {
 59→    expect(resolveContextPath(CONTEXT, 'tags.0')).toBe('premium');
 60→    expect(resolveContextPath(CONTEXT, 'tags.1')).toBe('active');
 61→  });
 62→
 63→  it('returns empty string for out-of-bounds array access', () => {
 64→    expect(resolveContextPath(CONTEXT, 'tags.99')).toBe('');
 65→    expect(resolveContextPath(CONTEXT, 'tags.-1')).toBe('');
 66→  });
 67→
 68→  it('returns empty string for non-numeric array index', () => {
 69→    expect(resolveContextPath(CONTEXT, 'tags.invalid')).toBe('');
 70→  });
 71→});
 72→
 73→describe('interpolateString', () => {
 74→  it('replaces single placeholder', () => {
 75→    expect(
 76→      interpolateString('Voucher para {{product.name}}', CONTEXT),
 77→    ).toBe('Voucher para Abastecimento');
 78→  });
 79→
 80→  it('replaces multiple placeholders', () => {
 81→    expect(
 82→      interpolateString(
 83→        '{{balance.pointsFormatted}} pontos = {{balance.valueFormatted}}',
 84→        CONTEXT,
 85→      ),
 86→    ).toBe('25.720 pontos = R$ 7.716,00');
 87→  });
 88→
 89→  it('replaces numeric values as strings', () => {
 90→    expect(
 91→      interpolateString('Código: {{product.code}}', CONTEXT),
 92→    ).toBe('Código: 206');
 93→  });
 94→
 95→  it('replaces missing values with empty string', () => {
 96→    expect(
 97→      interpolateString('Hello {{missing.path}}!', CONTEXT),
 98→    ).toBe('Hello !');
 99→  });
100→
101→  it('returns original string without placeholders', () => {
102→    expect(interpolateString('No placeholders here', CONTEXT)).toBe(
103→      'No placeholders here',
104→    );
105→  });
106→
107→  it('handles empty string', () => {
108→    expect(interpolateString('', CONTEXT)).toBe('');
109→  });
110→
111→  it('handles repeated placeholders', () => {
112→    expect(
113→      interpolateString('{{product.name}} vs {{product.name}}', CONTEXT),
114→    ).toBe('Abastecimento vs Abastecimento');
115→  });
116→
117→  it('returns empty string when placeholder resolves to object', () => {
118→    expect(interpolateString('Value: {{product}}', CONTEXT)).toBe('Value: ');
119→  });
120→
121→  it('returns empty string when placeholder resolves to array', () => {
122→    expect(interpolateString('Tags: {{tags}}', CONTEXT)).toBe('Tags: ');
123→  });
124→});
125→
126→describe('interpolateDeep', () => {
127→  it('interpolates string values in objects', () => {
128→    const input = {
129→      text: 'Voucher para {{product.name}}',
130→      label: 'Pontos: {{balance.pointsFormatted}}',
131→    };
132→    expect(interpolateDeep(input, CONTEXT)).toEqual({
133→      text: 'Voucher para Abastecimento',
134→      label: 'Pontos: 25.720',
135→    });
136→  });
137→
138→  it('interpolates strings in nested objects', () => {
139→    const input = {
140→      header: {
141→        title: '{{product.name}}',
142→        subtitle: '{{balance.valueFormatted}}',
143→      },
144→    };
145→    expect(interpolateDeep(input, CONTEXT)).toEqual({
146→      header: {
147→        title: 'Abastecimento',
148→        subtitle: 'R$ 7.716,00',
149→      },
150→    });
151→  });
152→
153→  it('interpolates strings in arrays', () => {
154→    const input = ['{{product.name}}', '{{product.key}}'];
155→    expect(interpolateDeep(input, CONTEXT)).toEqual([
156→      'Abastecimento',
157→      'abastecimento',
158→    ]);
159→  });
160→
161→  it('preserves non-string primitives', () => {
162→    const input = {
163→      count: 42,
164→      active: true,
165→      empty: null,
166→      text: '{{product.name}}',
167→    };
168→    expect(interpolateDeep(input, CONTEXT)).toEqual({
169→      count: 42,
170→      active: true,
171→      empty: null,
172→      text: 'Abastecimento',
173→    });
174→  });
175→
176→  it('handles deeply nested mixed structures', () => {
177→    const input = {
178→      body: [
179→        {
180→          type: 'heading',
181→          props: { text: '{{product.name}}' },
182→        },
183→        {
184→          type: 'balance',
185→          props: {
186→            points: '{{balance.pointsFormatted}}',
187→            nested: { value: '{{balance.valueFormatted}}' },
188→          },
189→        },
190→      ],
191→    };
192→    expect(interpolateDeep(input, CONTEXT)).toEqual({
193→      body: [
194→        {
195→          type: 'heading',
196→          props: { text: 'Abastecimento' },
197→        },
198→        {
199→          type: 'balance',
200→          props: {
201→            points: '25.720',
202→            nested: { value: 'R$ 7.716,00' },
203→          },
204→        },
205→      ],
206→    });
207→  });
208→
209→  it('returns primitive values unchanged', () => {
210→    expect(interpolateDeep(42, CONTEXT)).toBe(42);
211→    expect(interpolateDeep(true, CONTEXT)).toBe(true);
212→    expect(interpolateDeep(null, CONTEXT)).toBeNull();
213→  });
214→});
